function LWonderlordMap:InitEvent()
    self:MapEventRecv(EventNames.ON_WONDERLAND_PAGE_CHANGE,function ()
        self:RefreshBossShow()
    end)
end

function LWonderlordMap:RefreshBossShow()
    local monsterDataList = self._monsterDataList
    if not monsterDataList then
        return
    end
    for k,v in ipairs(self._monsterDataList) do
        local root = self._monsterRootList[k].transform
        local isFinish = gModelWonderland:IsTimeLordFinish(v)
        local tag = CS.FindTrans(root,"tag")
        CS.ShowObject(tag,isFinish)
    end

end


function LWonderlordMap:OnEnterMap()
    if not GF.FindFirstWndByName("UIEden") then
        GF.OpenWndBottom("UIEden")
    end


    self._data  = self:GetMapArg("data")

    local eventId = self._data.eventId
    local mapTran = self._mapTrans

    local themeId = gModelWonderland:GetThemeId()
    local themeCfg = gModelWonderland:GetThemeConfig(themeId)
    if not themeCfg then
        return
    end
    local bgPath= themeCfg.spacetime
    --local paths = string.split(bgPath,",")


    local layerRoot = CS.FindTrans(mapTran,"LayerRoot")
    local LayerBg = CS.FindTrans(layerRoot,"LayerBg")
    local bg_1 = CS.FindTrans(LayerBg,"bg_1")
    --local bg_2 = CS.FindTrans(LayerBg,"bg_2")
    --local bg_3 = CS.FindTrans(LayerBg,"bg_3")

    local dataList =
    {
        {trans = bg_1,spriteName = bgPath},
        --{trans = bg_2,spriteName = paths[2]},
        --{trans = bg_3,spriteName = paths[3]},

    }
    CS.ShowObject(layerRoot,false)
    self:SetSpriteList(dataList,function ()
        if not CS.IsValidObject(layerRoot) then
            return
        end
        CS.ShowObject(layerRoot,true)
    end)

    local effRoot = CS.FindTrans(layerRoot,"LayerEffect")
    self._effRoot = effRoot

    local objRoot = CS.FindTrans(layerRoot,"LayerObject")
    self._objRoot = objRoot

    self:InitCtrl()


    local monsterRoot_1 = CS.FindTrans(objRoot,"monsterRoot_1")
    local monsterRoot_2 = CS.FindTrans(objRoot,"monsterRoot_2")
    local monsterRoot_3 = CS.FindTrans(objRoot,"monsterRoot_3")

    self._monsterRootList =
    {
        [1] = monsterRoot_1,
        [2] = monsterRoot_2,
        [3] = monsterRoot_3
    }

    self._monsterDataList = gModelWonderland:GetTimeLordShow(eventId)


    if self._monsterDataList then
        for k,v in ipairs(self._monsterDataList) do
            self:CreateMonster(v,k)
        end
    end



    local roleGrid = CS.FindTrans(layerRoot,"GridRoot/roleGrid")
    self._roleGrid = roleGrid

    self:CreateRole()

    local gridPath = gModelWonderland:GetGridIconPath(themeId,StructWonderlandGrid.PLAYER)
    local grid = CS.FindTrans(roleGrid,"Root/GridIcon")
    self:SetSprite(grid,gridPath)
end



function LWonderlordMap:CreateMonster(eventId,index)

    local eventRef = gModelWonderland:GetEventConfig(eventId)

    local resName = eventRef.res
    local scale = eventRef.resSize
    local root = self._monsterRootList[index].transform
    local pos = root.position
    local data =
    {
        key = resName,
        resName = resName,
        pos = pos,
        scale = scale,
        sorting = LGamePlayType.WONDER_SORTING_STATE_RES,
        enableClick = true,
        endFunc = function(spine)
            local tran = spine:GetDisplayTrans()
            local collider = CS.FindTrans(tran,"Collider")
            CS.ShowObject(collider,false)
        end

    }

    self._objCtrl:MakeObject(data)
    local spriteTrans = CS.FindTrans(root,"nameBg")
    if spriteTrans then
        local sp = spriteTrans:GetComponent(typeOfSpriteRenderer)
        local sizeX = gLGameLanguage:IsForeignVersion() and 2.6 or 2.08
        sp.size = Vector2.New(sizeX,0.36)
    end

    local text = CS.FindTrans(root,"nameBg/UIText")
    local com = text:GetComponent(typeOfTextMesh)
    if com then
        --com.text = ccLngText(eventRef.name)
        self:SetXTextMeshProContent(text, ccLngText(eventRef.name))
        local renderer = com.renderer
        renderer.sortingLayerName = "Object"
        renderer.sortingOrder = 2
    end
    local effList = gModelWonderland:GetLordEffect()

    local effectRoot= CS.FindTrans(root,'array')
    for k,v in ipairs(effList) do
        local effData =
        {
            trans = effectRoot,
            key = string.format("monster_%s_%s",index,k),
            resName = v ,
            pos = Vector3.zero ,
            scale = 1,
            renderLayer = "EffectDown"
        }

        self._effCtrl:MakeObject(effData)
    end

    local isFinish = gModelWonderland:IsTimeLordFinish(eventId)
    local tag = CS.FindTrans(root,"tag")
    CS.ShowObject(tag,isFinish)

    self:SetBuildClick(root,function ()
        self:OnClickMonster(eventId,index)
    end)
end

function LWonderlordMap:CreateRole()
    local themeId = gModelWonderland:GetThemeId()
    local spineName = gModelWonderland:GetRoleRes(themeId)
    local pos = self._roleGrid.transform.position
    local data =
    {
        key = "mainRole",
        pos = pos,
        resName = spineName,
        scale = 0.7,
        endFunc = function (spine)
            spine:PlayAnimation(0,"idle",true)
        end,
    }
    self._objCtrl:MakeObject(data)

end

