function LWonderlordMap:OnClickMonster(eventId,index)
    local isFinish = gModelWonderland:IsTimeLordFinish(eventId)
    if isFinish then
        local str = ccClientText(24100)
        GF.ShowMessage(str)
        return
    end

    if not eventId then
        return
    end

    local data =
    {
        eventId = eventId,
        layerIndex = self._data.layerIndex,
        gridIndex = self._data.gridIndex,
        eventType = ModelWonderland.EVENT_TIME_LORD,
        state = self._data.state,
        canSelect = self._data.canSelect,
        index = index,
    }

    GF.OpenWnd("UIEdenMonster",{data= data ,wndType = 2})
end



function LWonderlordMap:SetSprite(trans,spriteName,endFunc)
    self:SetSpriteRenderer(trans, spriteName, endFunc)
end

function LWonderlordMap:SetSpriteList(dataList,endFunc)
    local cnt = #dataList
    for k,v in ipairs(dataList) do
        local trans = v.trans
        local spriteName = v.spriteName
        self:SetSprite(trans,spriteName,function ()
            cnt=cnt-1
            if cnt ==0 then
                if endFunc then
                    endFunc()
                end
            end
        end)
    end
end

function LWonderlordMap:InitCtrl()
    if not self._objCtrl then
        self._objCtrl = LWonderObjectCtrl:New()
    end
    self._objCtrl:InitCtrl(self._objRoot)

    if not self._effCtrl then
        self._effCtrl = LWonderEffectCtrl:New()
    end

    self._effCtrl:InitCtrl(self._effRoot)
end

function LWonderlordMap:Clear()
    if self._objCtrl then
        self._objCtrl:Clear()
        self._objCtrl = nil
    end

    if self._effCtrl then
        self._effCtrl:Clear()
        self._effCtrl = nil
    end
end


