function LWonderlordMap:InitCameraComponent()
    local layerRoot = CS.FindTrans(self._mapTrans,"LayerRoot")
    local com = layerRoot:GetComponent(typeofYXIMapCamera)
    self._mapCameraCom = com

    local range = self:GetCameraRange()

    self._mapCameraCom:SetRange(Vector2.New(0,range.x),Vector2.New(0,range.y))
end

function LWonderlordMap:GetCameraRange()
    local designWidth = LGameQuality.SCREEN_WIDTH_DESIGN-- 设计分辨率
    local designHeight = LGameQuality.SCREEN_HEIGHT_DESIGN-- 设计分辨率
    local pixelPreUnit = 100

    local designOrthgraphicSize = designHeight / pixelPreUnit * 0.5
    local orthgraphicSize = designOrthgraphicSize

    local UScreen = UnityEngine.Screen
    local screenWidth = UScreen.width
    local screenHeight = UScreen.height

    -- adapt by width
    local nowRate = screenWidth / screenHeight
    local  designRate = designWidth / designHeight
    if (nowRate >= designRate) then

    else
        orthgraphicSize = designRate / nowRate * designOrthgraphicSize
    end

    local min = orthgraphicSize - designOrthgraphicSize
    local max = 11.36+ designOrthgraphicSize - orthgraphicSize

    return Vector2.New(min,max)
end

function LWonderlordMap:UpdateMapVisible()
    if not self:IsMapValid() then
        return
    end


    LMapBase.UpdateMapVisible(self)
end



